import React, { useState } from 'react';

function Bio({ bio }) {
  const [sanitizedBio, setSanitizedBio] = useState('');

  // Sanitize the bio to prevent XSS attacks
  function sanitize(bio) {
    return bio.replace(/</g, '&lt;').replace(/>/g, '&gt;');
  }

  // Update the sanitized bio when the component mounts
  useEffect(() => {
    setSanitizedBio(sanitize(bio));
  }, [bio]);

  return <div dangerouslySetInnerHTML={{ __html: sanitizedBio }} />;
}